P = (0,0);
Q = (6,0);
R = (0,6*tan(acos(0.4)));
draw(P--Q--R--P);
draw(rightanglemark(Q,P,R,18));
label("$P$",P,SW);
label("$Q$",Q,SE);
label("$R$",R,N);
label("$12$",Q/2,S);
[/asy]

rationale:
